struct VendorUsageEntry: Codable, Equatable, Sendable {
    let vendor: String
    let account: String
    var isActive: Bool
    var lastAcquiredOn: String?
    var lastError: UsageError?
    var metrics: [UsageMetric]

    init(
        vendor: String,
        account: String,
        isActive: Bool = false,
        lastAcquiredOn: String? = nil,
        lastError: UsageError? = nil,
        metrics: [UsageMetric] = []
